# app/workflow/intent_recognizer.py
# Intent recognition: rule-based (Tier 0-3) then LLM fallback.
# Model: OpenAILike(id=settings.MODEL_ID, api_key=settings.DASHSCOPE_API_KEY, base_url=settings.DASHSCOPE_BASE_URL)

import re
from typing import Optional
from agno.agent import Agent
from agno.models.openai import OpenAILike
from app.config import settings
from app.schemas.intent import IntentResult, IntentType
from app.schemas.request import ContextItem
from app.workflow.path_types import extract_path_types_from_text, extract_target_value_from_text
from app.workflow.prompts.intent_prompt import INTENT_RECOGNITION_PROMPT

# --- Tier 0 rules (homepage sample phrases, regex) ---
_HOMEPAGE_RULES: list[tuple[re.Pattern, IntentType]] = [
    (re.compile(r"怎么达成.*NBEV.*目标", re.IGNORECASE), IntentType.nbev_planning),
    (re.compile(r"客户.*(?:画像|分布|结构|分层)"), IntentType.customer_portrait),
    (re.compile(r"客群.*(?:画像|分布|结构)"), IntentType.customer_portrait),
    (re.compile(r"(?:客温|客价).*(?:分布|画像)"), IntentType.customer_portrait),
    (re.compile(r"(?:队伍|团队).*(?:画像|分布|结构|分层|人力)"), IntentType.team_portrait),
    (re.compile(r"人力.*(?:画像|分布|结构)"), IntentType.team_portrait),
]

def try_homepage_intent(user_message: str) -> Optional[IntentResult]:
    """Match Tier 0 only. Returns final result (confidence=1.0) if matched."""
    msg = re.sub(r"\s+", "", user_message)
    for pattern, intent in _HOMEPAGE_RULES:
        if pattern.search(msg):
            return IntentResult(intent=intent, confidence=1.0, target_value=None, path_types=None)
    return None

def try_rule_based_intent(user_message: str, contexts: Optional[list[ContextItem]] = None) -> Optional[IntentResult]:
    """Tier 1-3 rule-based matching (context-aware)."""
    msg = re.sub(r"\s+", "", user_message)
    has_plan_ctx = _has_completed_planning_context(contexts)

    # Tier 1: adjust target after completed planning
    if has_plan_ctx and _is_target_adjustment_message(msg):
        return IntentResult(intent=IntentType.target_value_adjustment, confidence=1.0,
                            target_value=_extract_target_value_from_contexts(contexts), path_types=None)

    # Adjust measurement adjustments
    adj_paths = extract_path_types_from_text(user_message) or _extract_path_types_by_keywords(msg)
    if has_plan_ctx and adj_paths and _is_measurement_adjustment_message(msg):
        return IntentResult(intent=IntentType.achievement_measurement_adjustment, confidence=1.0,
                            target_value=_extract_target_value_from_contexts(contexts), path_types=adj_paths)

    # Fallback after planning
    if has_plan_ctx and _is_planning_fallback_message(msg):
        return IntentResult(intent=IntentType.nbev_planning_fallback, confidence=0.95,
                            target_value=_extract_target_value_from_contexts(contexts), path_types=adj_paths)

    # Tier 0: homepage (already standalone, but included)
    home_res = try_homepage_intent(user_message)
    if home_res:
        return home_res

    # Tier 2: structured extraction (target_value / path_types)
    tv = extract_target_value_from_text(user_message)
    pts = extract_path_types_from_text(user_message)
    if tv is not None or pts is not None:
        return IntentResult(intent=IntentType.nbev_planning, confidence=1.0, target_value=tv, path_types=pts)

    # Tier 3: keyword heuristic (NBEV + planning keywords)
    if "NBEV" in msg.upper() and any(kw in msg for kw in ("达成", "规划", "路径", "测算", "分析")):
        return IntentResult(intent=IntentType.nbev_planning, confidence=0.95, target_value=None, path_types=None)

    return None

try_shortcut_intent = try_rule_based_intent  # alias

def _has_completed_planning_context(contexts: Optional[list[ContextItem]]) -> bool:
    text = _contexts_text(contexts)
    markers = ("NEXT_STEP_CARD", "TEAM_REACH_MEASUREMENT", "CUSTOMER_REACH_MEASUREMEN",
               "PRODUCT_REACH_MEASUREMENT", "达成路径", "达成测算", "路径规划")
    return any(m in text for m in markers)

def _extract_target_value_from_contexts(contexts: Optional[list[ContextItem]]) -> Optional[str]:
    text = _contexts_text(contexts)
    for pat in (r'"targetNbev"\s*:\s*(\d+(?:\.\d+)?)', r'"target_nbev"\s*:\s*(\d+(?:\.\d+)?)',
                r'"target_value"\s*:\s*"?(\d+(?:\.\d+)?)"?', r"目标值?[^\d]*(\d+(?:\.\d+)?)\s*万",
                r"NBEV目标[^\d]*(\d+(?:\.\d+)?)\s*万"):
        m = re.search(pat, text, re.IGNORECASE)
        if m: return m.group(1)
    return extract_target_value_from_text(text)

def _is_target_adjustment_message(msg: str) -> bool:
    return any(k in msg for k in ("调整目标", "修改目标", "重设目标", "重新设置目标", "换个目标"))

def _extract_path_types_by_keywords(msg: str) -> Optional[list[str]]:
    paths = []
    if "队伍" in msg or "团队" in msg: paths.append("队伍")
    if "客户" in msg: paths.append("客户")
    if "产品" in msg: paths.append("产品")
    return paths or None

def _is_measurement_adjustment_message(msg: str) -> bool:
    return any(k in msg for k in ("重新测算", "重新规划", "规划", "测算")) and any(p in msg for p in ("队伍", "团队", "客户", "产品"))

def _is_planning_fallback_message(msg: str) -> bool:
    if not any(k in msg for k in ("调整", "修改", "改", "AI研判", "研判", "分析结果", "达成路径", "测算")): return False
    return any(k in msg for k in ("NBEV", "目标", "路径", "测算", "队伍", "团队", "客户", "产品", "分布", "研判"))

async def recognize_intent(user_message: str, contexts: Optional[list[ContextItem]] = None) -> IntentResult:
    """LLM-based intent recognition (fallback)."""
    ctx_str = "\n".join(f"用户: {c.query}\n助手: {c.answer}" for c in (contexts or []) if c.query or c.answer)
    if ctx_str: ctx_str = "\n\n## 对话上下文\n" + ctx_str
    agent = Agent(name="IntentRecognizer", model=_build_model(), instructions=INTENT_RECOGNITION_PROMPT,
                  output_schema=IntentResult, markdown=False, telemetry=False)
    prompt = f"用户消息：{user_message}{ctx_str}"
    resp = await agent.arun(prompt)
    if resp and resp.content and isinstance(resp.content, IntentResult):
        return resp.content
    return IntentResult(intent=IntentType.other, confidence=0.5)
```

